const body = $json.body ?? $json;
const portfolioMap = {
  "Breanna": ["Courtyard", "Adobe", "NorthPark"],
  "Amy": ["Jefferson", "Riveredge", "Crosskeys"],
  "Debbie": ["Sagebrush"],
  "Dede": ["Westminster", "Broadstone", "Nelson"],
  "Shelbie/Chris": ["Oak Terrace"],
  "Ashlie": ["Single Families and Small Multi"]
};

function isMonday(dateStr) {
  const d = new Date(`${dateStr}T00:00:00`);
  return !Number.isNaN(d.getTime()) && d.getDay() === 1;
}

function makeUuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

const requiredTop = ['manager_name', 'week_start_date', 'submitted_at', 'properties'];
for (const field of requiredTop) {
  if (!(field in body)) {
    throw new Error(`Missing top-level field: ${field}`);
  }
}

if (!portfolioMap[body.manager_name]) {
  throw new Error(`Invalid manager_name: ${body.manager_name}`);
}

if (!isMonday(body.week_start_date)) {
  throw new Error('week_start_date must be a Monday');
}

if (!Array.isArray(body.properties) || body.properties.length === 0) {
  throw new Error('properties must be a non-empty array');
}

const expectedProperties = new Set(portfolioMap[body.manager_name]);
const seenProperties = new Set();

const submittedAt = new Date(body.submitted_at);
if (Number.isNaN(submittedAt.getTime())) {
  throw new Error('submitted_at must be a valid ISO timestamp');
}

const mondayCutoff = new Date(`${body.week_start_date}T10:00:00-05:00`);
const lateSubmission = submittedAt > mondayCutoff ? 1 : 0;

const rows = body.properties.map((row) => {
  const requiredNumeric = [
    'vacant_units',
    'ready_vacants',
    'not_ready_vacants',
    'delinquent_count',
    'delinquent_amount',
    'turns_in_progress',
    'work_orders_over_7_days'
  ];
  const requiredText = ['property_name', 'biggest_issue_text', 'help_needed_text'];

  for (const field of requiredNumeric) {
    if (!(field in row)) throw new Error(`Missing required numeric field: ${field}`);
    const num = Number(row[field]);
    if (Number.isNaN(num) || num < 0) throw new Error(`Invalid numeric value for ${field} on ${row.property_name}`);
  }

  for (const field of requiredText) {
    if (!(field in row) || !String(row[field]).trim()) {
      throw new Error(`Missing required text field: ${field} on ${row.property_name ?? 'unknown property'}`);
    }
  }

  if (Number(row.vacant_units) !== Number(row.ready_vacants) + Number(row.not_ready_vacants)) {
    throw new Error(`Vacancy split mismatch on ${row.property_name}`);
  }

  if (!expectedProperties.has(row.property_name)) {
    throw new Error(`Property ${row.property_name} is not assigned to ${body.manager_name}`);
  }
  if (seenProperties.has(row.property_name)) {
    throw new Error(`Duplicate property row: ${row.property_name}`);
  }
  seenProperties.add(row.property_name);

  return {
    id: makeUuid(),
    manager_name: body.manager_name,
    week_start_date: body.week_start_date,
    property_name: row.property_name,
    vacant_units: Number(row.vacant_units),
    ready_vacants: Number(row.ready_vacants),
    not_ready_vacants: Number(row.not_ready_vacants),
    delinquent_count: Number(row.delinquent_count),
    delinquent_amount: Number(Number(row.delinquent_amount).toFixed(2)),
    turns_in_progress: Number(row.turns_in_progress),
    work_orders_over_7_days: Number(row.work_orders_over_7_days),
    biggest_issue_text: String(row.biggest_issue_text).trim(),
    help_needed_text: String(row.help_needed_text).trim(),
    struggling_units_text: row.struggling_units_text ? String(row.struggling_units_text).trim() : null,
    late_submission: lateSubmission,
    created_at: new Date().toISOString().slice(0, 19).replace('T', ' ')
  };
});

for (const property of expectedProperties) {
  if (!seenProperties.has(property)) {
    throw new Error(`Missing assigned property row: ${property}`);
  }
}

return rows.map(r => ({ json: r }));

